// Extract the image URL and file info from Manus output
const output = $input.first().json.output || [];
let imageUrl = null;
let imageFileName = null;
let assistantMessage = '';

for (const item of output) {
  if (item.content) {
    for (const content of item.content) {
      if (content.type === 'output_file') {
        imageUrl = content.fileUrl;
        imageFileName = content.fileName;
      }
      if (content.type === 'output_text' && item.role === 'assistant') {
        assistantMessage = content.text;
      }
    }
  }
}

// Get concept info from earlier in the chain
const concept = $('Generate Concept').item.json;

return [{
  json: {
    ...concept,
    image_url: imageUrl,
    image_filename: imageFileName,
    manus_task_id: $input.first().json.id,
    manus_share_url: $input.first().json.metadata?.share_url,
    manus_response: assistantMessage,
    credit_usage: $input.first().json.credit_usage
  }
}];

parameters.jsonBody:
={
  "prompt": "You are the social media manager for @pawcasso.atelier, an Instagram account that posts AI-generated artistic animal portraits. Write an Instagram caption for this post:

Concept: {{ $json.concept }}
Art Style: {{ $json.style }}
Content Pillar: {{ $json.pillar }}
Animal: {{ $json.animal }}

Caption rules:
1. Start with a HOOK LINE — punchy, funny, or intriguing (1 sentence max)
2. Add 1-2 sentences of CONTEXT about the piece
3. End with an ENGAGEMENT PROMPT — a question or CTA that invites comments
4. Tone: Witty, warm, slightly irreverent. Like a clever friend who's an artist.
5. Keep under 150 words total
6. Do NOT mention AI or that the art is AI-generated

Also generate 20-25 relevant hashtags in 3 tiers:
- Branded: #PawcassoAtelier #PawcassoDaily #PaintedByPawcasso
- Broad reach (5-7): from #DigitalArt #ArtOfTheDay #AnimalArt etc.
- Niche (10-12): from #AIGeneratedArt #AnimalPortrait #FantasyArt etc.

Return ONLY a JSON object with this exact format (no markdown, no explanation):
{
  "caption": "the caption text",
  "hashtags": "#tag1 #tag2 ...all hashtags...",
  "hook": "just the hook line for preview"
}",
  "agentProfile": "manus-1.6-max",
  "autoStart": true
}

parameters.jsCode:
// Extract caption from Manus response and compile the review package
const captionOutput = $input.first().json.output || [];
let captionText = '';

for (const item of captionOutput) {
  if (item.content && item.role === 'assistant') {
    for (const content of item.content) {
      if (content.type === 'output_text') {
        captionText += content.text;
      }
    }
  }
}

// Try to parse JSON from caption text
let caption = '';
let hashtags = '';
let hook = '';

try {
  const jsonMatch = captionText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    caption = parsed.caption || captionText;
    hashtags = parsed.hashtags || '';
    hook = parsed.hook || '';
  } else {
    caption = captionText;
  }
} catch (e) {
  caption = captionText;
}

const concept = $('Extract Image URL').item.json;

return [{
  json: {
    date: concept.date,
    pillar: concept.pillar,
    style: concept.style,
    animal: concept.animal,
    concept: concept.concept,
    image_url: concept.image_url,
    image_filename: concept.image_filename,
    manus_share_url: concept.manus_share_url,
    caption: caption,
    hashtags: hashtags,
    hook: hook,
    total_credits: (concept.credit_usage || 0) + ($input.first().json.credit_usage || 0),
    status: 'pending_review'
  }
}];

